GradeConfig = {}

GradeConfig.Grade = {}

function GradeConfig:init(config)
    for _, gradeItem in pairs(config) do
        local data = {}
        data.Id = tonumber(gradeItem.Id)
        data.Score = tonumber(gradeItem.Score)
        data.Grade = tostring(gradeItem.Grade)
        self.Grade[data.Id] = data
    end
end

function GradeConfig:findGradeByScore(score)
    local min = nil
    local index = 0
    for _, gradeItem in pairs(self.Grade) do
        if min == nil then
            min = gradeItem.Score
            index = gradeItem.Id
        else
            if min > gradeItem.Score then
                min = gradeItem.Score
                index = gradeItem.Id
            end
        end
    end
    for _, gradeItem in pairs(self.Grade) do
        if gradeItem.Score <= score and gradeItem.Score > min then
            min = gradeItem.Score
            index = gradeItem.Id
        end
    end
    return self.Grade[index].Grade
end